#! /bin/bash

echo "++++++++++++++++"
echo "DOTFILES INSTALL"
echo "++++++++++++++++"

cd $HOME

SOURCE_FILE='.dotfiles-source'
SOURCE_COMMAND="source $SOURCE_FILE"

if ! grep -Fxq "$SOURCE_COMMAND" .bashrc; then
  echo "$SOURCE_COMMAND" >> .bashrc
fi

cat <<'SOURCE' > $SOURCE_FILE
# THIS FILE IS GENERATED BY ~/.dotfiles-modules/install.sh
# ---
# DO NOT TRACK IN GIT
# ---
# DO NOT MANUALLY EDIT
#

SOURCE

echo 'source .dotfiles-modules/dotfiles/dotfiles.sh' >> $SOURCE_FILE

